import React, { useState } from "react";

function NewsImpactPage() {
  const [newsText, setNewsText] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    if (!newsText.trim()) {
      alert("Please enter some news text.");
      return;
    }

    setLoading(true);
    try {
      const response = await fetch("http://localhost:3000/api/news-impact", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ text: newsText }),
      });

      const data = await response.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Error analyzing news impact.");
    }
    setLoading(false);
  };

  return (
    <div style={{ padding: "2rem", fontFamily: "Arial" }}>
      <h1>News Impact Analysis</h1>
      <textarea
        rows={6}
        style={{ width: "100%", marginBottom: "1rem" }}
        placeholder="Paste financial news text here..."
        value={newsText}
        onChange={(e) => setNewsText(e.target.value)}
      />

      <button onClick={handleSubmit} disabled={loading}>
        {loading ? "Analyzing..." : "Analyze Impact"}
      </button>

      {result && (
        <div style={{ marginTop: "2rem", border: "1px solid #ddd", padding: "1rem" }}>
          <h3>Prediction</h3>
          <p><strong>Impact:</strong> {result.prediction}</p>
          <p><strong>Confidence:</strong> {(result.confidence * 100).toFixed(2)}%</p>
          <p><strong>Original Text:</strong> {result.original_news}</p>
        </div>
      )}
    </div>
  );
}

export default NewsImpactPage;
